1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Base premiums for single main items (base + 5 fee, newcomer: +10% first ins) ---
6	  // To isolate base premiums we use a long-standing customer's follow-up contract where
7	  // policy-wide modifiers are exercised separately; here we cover the raw base premium rule.
8	
9	  // Edge case: empty item list
10	  it("empty item list → premium 5 (only processing fee)", () => {
11	    const result = runScenario({
12	      customer: { yearsWithMHPCO: 0 },
13	      steps: [{ op: "quote", items: [] }],
14	    });
15	    expect(result.results[0]).toEqual({ premium: 5 });
16	  });
17	
18	  // Building block base premiums (components) — isolated base premium values
19	  it("2 runes → 50 G base premium", () => {
20	    const result = runScenario({
21	      customer: { yearsWithMHPCO: 0 },
22	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
23	    });
24	    // base 50 (2×25, no block) + 10% first insurance = 55, + 5 fee = 60
25	    expect(result.results[0]).toEqual({ premium: 60 });
26	  });
27	  it.todo("3 runes → 60 G base premium (block applies)");
28	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
29	  it.todo("7 runes → 175 G base premium");
30	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
31	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
32	
33	  // Integration: premium modifiers stacking
34	  it.todo("newcomer cursed sword (0 yrs, steel, ench 3) → premium 165");
35	  it.todo("long-standing customer 2nd contract (3 yrs, cursed sword steel ench 7) → premium 160");
36	
37	  // Modifier thresholds
38	  it.todo("customer with exactly 2 years → loyalty discount applies");
39	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
40	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
41	  it.todo("cursed sword with exactly enchantment 5 → both curse and high-enchant surcharges apply");
42	
43	  // Modifier scope on multi-item policies
44	  it.todo("cursed sword + plain amulet → 210 G before further modifiers and fee (curse on item base only)");
45	
46	  // Rounding
47	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
48	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
49	
50	  // --- Claim processing ---
51	
52	  // Standard reimbursement (no special clauses)
53	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
54	  it.todo("rune (value 250), damage 200 → payout 100 (full minus 100 deductible, no special clause)");
55	
56	  // High enchantment clause
57	  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");
58	
59	  // Dragon material clause
60	  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (full then deductible)");
61	
62	  // Both clauses — 50% wins
63	  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% wins, then deductible)");
64	  it.todo("dragon-material sword, exactly enchantment 8, damage 1000 → payout 400 (high-enchant applies, then deductible)");
65	
66	  // Deductible per damage event
67	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");
68	
69	  // Cap / insurance sum
70	  it.todo("policy covers sword + amulet → insurance sum 1600, cap 3200");
71	  it.todo("cursed sword → cap 2000 (based on unmodified insurance value)");
72	  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 (block discount does not affect sum)");
73	
74	  // Cap exhaustion across successive claims
75	  it.todo("sword (cap 2000), two claims of 1500 each → first payout 1400 remaining 600, second payout 600 remaining 0");
76	
77	  // Multiple items of same type
78	  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
79	  it.todo("dragon attack damages both swords (two sword damages) → each treated as separate damage with own deductible");
80	  it.todo("more sword damages than swords insured → claim rejected (throws)");
81	
82	  // CLI / error cases
83	  it.todo("quote with unknown item type (broomstick) → throws");
84	  it.todo("claim references item not in policy (amulet damaged, only sword insured) → throws");
85	  it.todo("claim references item with unknown type → throws");
86	  it.todo("claim damage amount negative (-200) → throws");
